# --- GraphQL Types ---

class ReviewType(graphene.ObjectType):
    id = graphene.ID(required=True)
    product_id = graphene.ID(required=True)
    user_id = graphene.ID(required=True)
    username = graphene.String(required=True)
    rating = graphene.Int(required=True)
    title = graphene.String(required=True)
    comment = graphene.String()
    is_verified_purchase = graphene.Boolean()
    helpful_count = graphene.Int()
    created_at = graphene.String()

    def resolve_product(self, info):
        product_data = next((p for p in PRODUCTS if p["id"] == self.product_id), None)
        if product_data:
            return ProductType(**product_data)
        return None


class ReviewConnection(graphene.ObjectType):
    items = graphene.List(ReviewType, required=True)
    total_count = graphene.Int(required=True)
    average_rating = graphene.Float()
    rating_distribution = graphene.JSONString()


class CategoryType(graphene.ObjectType):
    id = graphene.ID(required=True)
    name = graphene.String(required=True)
    description = graphene.String()
    slug = graphene.String(required=True)
    parent_id = graphene.ID()
    parent = graphene.Field(lambda: CategoryType)
    subcategories = graphene.List(lambda: CategoryType)
    product_count = graphene.Int()
    products = graphene.List(lambda: ProductType, limit=graphene.Int(default_value=10), offset=graphene.Int(default_value=0))

    def resolve_parent(self, info):
        if self.parent_id:
            parent_data = next((c for c in CATEGORIES if c["id"] == self.parent_id), None)
            if parent_data:
                return CategoryType(**parent_data)
        return None

    def resolve_subcategories(self, info):
        subs = [c for c in CATEGORIES if c["parent_id"] == self.id]
        return [CategoryType(**c) for c in subs]

    def resolve_product_count(self, info):
        # Count products in this category and all subcategories
        category_ids = [self.id]
        sub_ids = [c["id"] for c in CATEGORIES if c["parent_id"] == self.id]
        category_ids.extend(sub_ids)
        return len([p for p in PRODUCTS if p["category_id"] in category_ids])

    def resolve_products(self, info, limit=10, offset=0):
        category_ids = [self.id]
        sub_ids = [c["id"] for c in CATEGORIES if c["parent_id"] == self.id]
        category_ids.extend(sub_ids)
        prods = [p for p in PRODUCTS if p["category_id"] in category_ids]
        return [ProductType(**p) for p in prods[offset:offset + limit]]


class PriceRange(graphene.ObjectType):
    min_price = graphene.Float(required=True)
    max_price = graphene.Float(required=True)
    currency = graphene.String(required=True)


class ProductType(graphene.ObjectType):
    id = graphene.ID(required=True)
    name = graphene.String(required=True)
    description = graphene.String()
    price = graphene.Float(required=True)
    sale_price = graphene.Float()
    sku = graphene.String(required=True)
    category_id = graphene.ID(required=True)
    category = graphene.Field(CategoryType)
    stock_quantity = graphene.Int()
    is_active = graphene.Boolean()
    is_in_stock = graphene.Boolean()
    brand = graphene.String()
    weight = graphene.Float()
    dimensions = graphene.String()
    image_url = graphene.String()
    tags = graphene.List(graphene.String)
    created_at = graphene.String()
    updated_at = graphene.String()
    effective_price = graphene.Float()
    discount_percentage = graphene.Float()
    reviews = graphene.Field(
        ReviewConnection,
        limit=graphene.Int(default_value=10),
        offset=graphene.Int(default_value=0),
        min_rating=graphene.Int(),
        sort_by=graphene.String(default_value="created_at")
    )

    def resolve_category(self, info):
        cat_data = next((c for c in CATEGORIES if c["id"] == self.category_id), None)
        if cat_data:
            return CategoryType(**cat_data)
        return None

    def resolve_is_in_stock(self, info):
        return (self.stock_quantity or 0) > 0

    def resolve_effective_price(self, info):
        if self.sale_price is not None:
            return self.sale_price
        return self.price

    def resolve_discount_percentage(self, info):
        if self.sale_price is not None and self.price > 0:
            return round(((self.price - self.sale_price) / self.price) * 100, 2)
        return 0.0

    def resolve_reviews(self, info, limit=10, offset=0, min_rating=None, sort_by="created_at"):
        product_reviews = [r for r in REVIEWS if r["product_id"] == self.id]

        if min_rating is not None:
            product_reviews = [r for r in product_reviews if r["rating"] >= min_rating]

        if sort_by == "rating":
            product_reviews.sort(key=lambda r: r["rating"], reverse=True)
        elif sort_by == "helpful":
            product_reviews.sort(key=lambda r: r.get("helpful_count", 0), reverse=True)
        else:
            product_reviews.sort(key=lambda r: r["created_at"], reverse=True)

        total = len(product_reviews)
        paginated = product_reviews[offset:offset + limit]

        # Calculate average rating from ALL reviews for this product (not filtered)
        all_product_reviews = [r for r in REVIEWS if r["product_id"] == self.id]
        avg_rating = None
        rating_dist = {}
        if all_product_reviews:
            avg_rating = round(sum(r["rating"] for r in all_product_reviews) / len(all_product_reviews), 2)
            for i in range(1, 6):
                rating_dist[str(i)] = len([r for r in all_product_reviews if r["rating"] == i])

        return ReviewConnection(
            items=[ReviewType(**r) for r in paginated],
            total_count=total,
            average_rating=avg_rating,
            rating_distribution=rating_dist if rating_dist else None
        )


class ProductConnection(graphene.ObjectType):
    items = graphene.List(ProductType, required=True)
    total_count = graphene.Int(required=True)
    page_info = graphene.Field(lambda: PageInfo)
    price_range = graphene.Field(PriceRange)


class PageInfo(graphene.ObjectType):
    has_next_page = graphene.Boolean(required=True)
    has_previous_page = graphene.Boolean(required=True)
    total_pages = graphene.Int(required=True)
    current_page = graphene.Int(required=True)


class UserType(graphene.ObjectType):
    id = graphene.ID(required=True)
    username = graphene.String(required=True)
    email = graphene.String()
    full_name = graphene.String()
    joined_at = graphene.String()
    review_count = graphene.Int()
    reviews = graphene.List(ReviewType, limit=graphene.Int(default_value=10))

    def resolve_review_count(self, info):
        return len([r for r in REVIEWS if r["user_id"] == self.id])

    def resolve_reviews(self, info, limit=10):
        user_reviews = [r for r in REVIEWS if r["user_id"] == self.id]
        return [ReviewType(**r) for r in user_reviews[:limit]]


# --- Enum types for sorting ---

class ProductSortField(graphene.Enum):
    NAME = "name"
    PRICE = "price"
    CREATED_AT = "created_at"
    RATING = "rating"


class SortOrder(graphene.Enum):
    ASC = "asc"
    DESC = "desc"


# --- Input types for filtering ---

class ProductFilterInput(graphene.InputObjectType):
    category_id = graphene.ID()
    category_slug = graphene.String()
    brand = graphene.String()
    min_price = graphene.Float()
    max_price = graphene.Float()
    is_active = graphene.Boolean()
    is_in_stock = graphene.Boolean()
    tags = graphene.List(graphene.String)
    search = graphene.String()
    on_sale = graphene.Boolean()


# --- Query ---

class Query(graphene.ObjectType):
    # Product queries
    product = graphene.Field(
        ProductType,
        id=graphene.ID(),
        sku=graphene.String(),
        description="Fetch a single product by ID or SKU"
    )
    products = graphene.Field(
        ProductConnection,
        filter=graphene.Argument(ProductFilterInput),
        limit=graphene.Int(default_value=10),
        offset=graphene.Int(default_value=0),
        sort_by=graphene.Argument(ProductSortField, default_value="created_at"),
        sort_order=graphene.Argument(SortOrder, default_value="desc"),
        description="Fetch a paginated list of products with filtering and sorting"
    )

    # Category queries
    category = graphene.Field(
        CategoryType,
        id=graphene.ID(),
        slug=graphene.String(),
        description="Fetch a single category by ID or slug"
    )
    categories = graphene.List(
        CategoryType,
        top_level_only=graphene.Boolean(default_value=False),
        description="Fetch all categories, optionally only top-level ones"
    )

    # Review queries
    review = graphene.Field(
        ReviewType,
        id=graphene.ID(required=True),
        description="Fetch a single review by ID"
    )
    reviews = graphene.Field(
        ReviewConnection,
        product_id=graphene.ID(),
        user_id=graphene.ID(),
        min_rating=graphene.Int(),
        limit=graphene.Int(default_value=10),
        offset=graphene.Int(default_value=0),
        description="Fetch reviews with optional filtering"
    )

    # User queries
    user = graphene.Field(
        UserType,
        id=graphene.ID(),
        username=graphene.String(),
        description="Fetch a user by ID or username"
    )

    # Search
    search_products = graphene.List(
        ProductType,
        query=graphene.String(required=True),
        limit=graphene.Int(default_value=10),
        description="Full-text search across product names, descriptions, brands, and tags"
    )

    # Analytics
    product_stats = graphene.Field(
        lambda: ProductStats,
        description="Get overall product catalog statistics"
    )

    def resolve_product(self, info, id=None, sku=None):
        if id:
            data = next((p for p in PRODUCTS if p["id"] == id), None)
        elif sku:
            data = next((p for p in PRODUCTS if p["sku"] == sku), None)
        else:
            return None
        if data:
            return ProductType(**data)
        return None

    def resolve_products(self, info, filter=None, limit=10, offset=0, sort_by="created_at", sort_order="desc"):
        filtered = list(PRODUCTS)

        if filter:
            if filter.category_id:
                # Include subcategory products
                cat_ids = [filter.category_id]
                sub_ids = [c["id"] for c in CATEGORIES if c["parent_id"] == filter.category_id]
                cat_ids.extend(sub_ids)
                filtered = [p for p in filtered if p["category_id"] in cat_ids]

            if filter.category_slug:
                cat = next((c for c in CATEGORIES if c["slug"] == filter.category_slug), None)
                if cat:
                    cat_ids = [cat["id"]]
                    sub_ids = [c["id"] for c in CATEGORIES if c["parent_id"] == cat["id"]]
                    cat_ids.extend(sub_ids)
                    filtered = [p for p in filtered if p["category_id"] in cat_ids]
                else:
                    filtered = []

            if filter.brand:
                filtered = [p for p in filtered if p.get("brand", "").lower() == filter.brand.lower()]

            if filter.min_price is not None:
                filtered = [p for p in filtered if (p.get("sale_price") or p["price"]) >= filter.min_price]

            if filter.max_price is not None:
                filtered = [p for p in filtered if (p.get("sale_price") or p["price"]) <= filter.max_price]

            if filter.is_active is not None:
                filtered = [p for p in filtered if p.get("is_active") == filter.is_active]

            if filter.is_in_stock is not None:
                if filter.is_in_stock:
                    filtered = [p for p in filtered if (p.get("stock_quantity", 0) or 0) > 0]
                else:
                    filtered = [p for p in filtered if (p.get("stock_quantity", 0) or 0) == 0]

            if filter.tags:
                filtered = [p for p in filtered if any(t in (p.get("tags") or []) for t in filter.tags)]

            if filter.search:
                query = filter.search.lower()
                filtered = [p for p in filtered if (
                    query in p["name"].lower() or
                    query in (p.get("description") or "").lower() or
                    query in (p.get("brand") or "").lower() or
                    any(query in t for t in (p.get("tags") or []))
                )]

            if filter.on_sale is not None:
                if filter.on_sale:
                    filtered = [p for p in filtered if p.get("sale_price") is not None]
                else:
                    filtered = [p for p in filtered if p.get("sale_price") is None]

        # Sorting
        sort_key = sort_by if isinstance(sort_by, str) else sort_by.value
        reverse = (sort_order == "desc") if isinstance(sort_order, str) else (sort_order.value == "desc")

        if sort_key == "rating":
            def get_avg_rating(p):
                prod_reviews = [r for r in REVIEWS if r["product_id"] == p["id"]]
                if not prod_reviews:
                    return 0
                return sum(r["rating"] for r in prod_reviews) / len(prod_reviews)
            filtered.sort(key=get_avg_rating, reverse=reverse)
        elif sort_key == "price":
            filtered.sort(key=lambda p: p.get("sale_price") or p["price"], reverse=reverse)
        else:
            filtered.sort(key=lambda p: p.get(sort_key, ""), reverse=reverse)

        total = len(filtered)
        paginated = filtered[offset:offset + limit]

        total_pages = max(1, -(-total // limit))  # Ceiling division
        current_page = (offset // limit) + 1

        # Price range for filtered results
        prices = [(p.get("sale_price") or p["price"]) for p in filtered]
        price_range = None
        if prices:
            price_range = PriceRange(
                min_price=min(prices),
                max_price=max(prices),
                currency="USD"
            )

        return ProductConnection(
            items=[ProductType(**p) for p in paginated],
            total_count=total,
            page_info=PageInfo(
                has_next_page=(offset + limit) < total,
                has_previous_page=offset > 0,
                total_pages=total_pages,
                current_page=current_page
            ),
            price_range=price_range
        )

    def resolve_category(self, info, id=None, slug=None):
        if id:
            data = next((c for c in CATEGORIES if c["id"] == id), None)
        elif slug:
            data = next((c for c in CATEGORIES if c["slug"] == slug), None)
        else:
            return None
        if data:
            return CategoryType(**data)
        return None

    def resolve_categories(self, info, top_level_only=False):
        if top_level_only:
            cats = [c for c in CATEGORIES if c["parent_id"] is None]
        else:
            cats = CATEGORIES
        return [CategoryType(**c) for c in cats]

    def resolve_review(self, info, id):
        data = next((r for r in REVIEWS if r["id"] == id), None)
        if data:
            return ReviewType(**data)
        return None

    def resolve_reviews(self, info, product_id=None, user_id=None, min_rating=None, limit=10, offset=0):
        filtered = list(REVIEWS)

        if product_id:
            filtered = [r for r in filtered if r["product_id"] == product_id]
        if user_id:
            filtered = [r for r in filtered if r["user_id"] == user_id]
        if min_rating is not None:
            filtered = [r for r in filtered if r["rating"] >= min_rating]

        filtered.sort(key=lambda r: r["created_at"], reverse=True)

        total = len(filtered)
        paginated = filtered[offset:offset + limit]

        avg_rating = None
        rating_dist = {}
        if filtered:
            avg_rating = round(sum(r["rating"] for r in filtered) / len(filtered), 2)
            for i in range(1, 6):
                rating_dist[str(i)] = len([r for r in filtered if r["rating"] == i])

        return ReviewConnection(
            items=[ReviewType(**r) for r in paginated],
            total_count=total,
            average_rating=avg_rating,
            rating_distribution=rating_dist if rating_dist else None
        )

    def resolve_user(self, info, id=None, username=None):
        if id:
            data = next((u for u in USERS if u["id"] == id), None)
        elif username:
            data = next((u for u in USERS if u["username"] == username), None)
        else:
            return None
        if data:
            return UserType(**data)
        return None

    def resolve_search_products(self, info, query, limit=10):
        query_lower = query.lower()
        results = []
        for p in PRODUCTS:
            score = 0
            if query_lower in p["name"].lower():
                score += 3
            if query_lower in (p.get("description") or "").lower():
                score += 1
            if query_lower == (p.get("brand") or "").lower():
                score += 2
            if any(query_lower in t for t in (p.get("tags") or [])):
                score += 1
            if score > 0:
                results.append((score, p))

        results.sort(key=lambda x: x[0], reverse=True)
        return [ProductType(**p) for _, p in results[:limit]]

    def resolve_product_stats(self, info):
        return ProductStats()


class ProductStats(graphene.ObjectType):
    total_products = graphene.Int()
    active_products = graphene.Int()
    out_of_stock_products = graphene.Int()
    total_reviews = graphene.Int()
    average_product_rating = graphene.Float()
    total_categories = graphene.Int()
    brands = graphene.List(graphene.String)
    price_range = graphene.Field(PriceRange)

    def resolve_total_products(self, info):
        return len(PRODUCTS)

    def resolve_active_products(self, info):
        return len([p for p in PRODUCTS if p.get("is_active")])

    def resolve_out_of_stock_products(self, info):
        return len([p for p in PRODUCTS if (p.get("stock_quantity", 0) or 0) == 0])

    def resolve_total_reviews(self, info):
        return len(REVIEWS)

    def resolve_average_product_rating(self, info):
        if REVIEWS:
            return round(sum(r["rating"] for r in REVIEWS) / len(REVIEWS), 2)
        return None

    def resolve_total_categories(self, info):
        return len(CATEGORIES)

    def resolve_brands(self, info):
        return list(set(p.get("brand") for p in PRODUCTS if p.get("brand")))

    def resolve_price_range(self, info):
        prices = [p["price"] for p in PRODUCTS]
        if prices:
            return PriceRange(min_price=min(prices), max_price=max(prices), currency="USD")
        return None


# --- Mutations ---

class CreateReviewInput(graphene.InputObjectType):
    product_id = graphene.ID(required=True)
    user_id = graphene.ID(required=True)
    rating = graphene.Int(required=True)
    title = graphene.String(required=True)
    comment = graphene.String()


class CreateReview(graphene.Mutation):
    class Arguments:
        input = CreateReviewInput(required=True)

    review = graphene.Field(ReviewType)
    ok = graphene.Boolean()
    message = graphene.String()

    def mutate(self, info, input):
        # Validate product exists
        product = next((p for p in PRODUCTS if p["id"] == input.product_id), None)
        if not product:
            return CreateReview(review=None, ok=False, message="Product not found")

        # Validate user exists
        user = next((u for u in USERS if u["id"] == input.user_id), None)
        if not user:
            return CreateReview(review=None, ok=False, message="User not found")

        # Validate rating
        if not 1 <= input.rating <= 5:
            return CreateReview(review=None, ok=False, message="Rating must be between 1 and 5")

        new_id = str(max(int(r["id"]) for r in REVIEWS) + 1)
        new_review = {
            "id": new_id,
            "product_id": input.product_id,
            "user_id": input.user_id,
            "username": user["username"],
            "rating": input.rating,
            "title": input.title,
            "comment": input.comment or "",
            "is_verified_purchase": False,
            "helpful_count": 0,
            "created_at": datetime.utcnow().isoformat()
        }
        REVIEWS.append(new_review)
        return CreateReview(review=ReviewType(**new_review), ok=True, message="Review created successfully")


class MarkReviewHelpful(graphene.Mutation):
    class Arguments:
        review_id = graphene.ID(required=True)

    review = graphene.Field(ReviewType)
    ok = graphene.Boolean()

    def mutate(self, info, review_id):
        review = next((r for r in REVIEWS if r["id"] == review_id), None)
        if not review:
            return MarkReviewHelpful(review=None, ok=False)
        review["helpful_count"] = review.get("helpful_count", 0) + 1
        return MarkReviewHelpful(review=ReviewType(**review), ok=True)


class UpdateProductStock(graphene.Mutation):
    class Arguments:
        product_id = graphene.ID(required=True)
        quantity = graphene.Int(required=True)

    product = graphene.Field(ProductType)
    ok = graphene.Boolean()
    message = graphene.String()

    def mutate(self, info, product_id, quantity):
        product = next((p for p in PRODUCTS if p["id"] == product_id), None)
        if not product:
            return UpdateProductStock(product=None, ok=False, message="Product not found")

        if quantity < 0:
            return UpdateProductStock(product=None, ok=False, message="Quantity cannot be negative")

        product["stock_quantity"] = quantity
        product["is_active"] = quantity > 0
        product["updated_at"] = datetime.utcnow().isoformat()
        return UpdateProductStock(product=ProductType(**product), ok=True, message="Stock updated successfully")


class Mutation(graphene.ObjectType):
    create_review = CreateReview.Field(description="Create a new product review")
    mark_review_helpful = MarkReviewHelpful.Field(description="Mark a review as helpful")
    update_product_stock = UpdateProductStock.Field(description="Update product stock quantity")


# --- Schema ---

schema = graphene.Schema(
    query=Query,
    mutation=Mutation,
    description="E-Commerce Product Catalog API - Provides access to products, categories, reviews, and user data."
)


